import { describe, expect, it } from "vitest";
import { mergeIntervals } from "../src/merge.js";

describe("mergeIntervals", () => {
  // --- empty ---
  it("returns [] for empty input", () => {
    // Catches: mishandling the empty case (e.g. returning undefined or [[undefined]]).
    expect(mergeIntervals([])).toEqual([]);
  });

  // --- single interval ---
  it("returns a single interval unchanged (by value)", () => {
    // Catches: dropping the last/only interval, or altering its bounds.
    expect(mergeIntervals([[1, 5]])).toEqual([[1, 5]]);
  });

  // --- overlapping ---
  it("merges overlapping intervals into one", () => {
    // Catches: failure to combine [1,4] and [3,6] into [1,6].
    expect(mergeIntervals([[1, 4], [3, 6]])).toEqual([[1, 6]]);
  });

  it("merges when the second interval is fully contained in the first", () => {
    // Catches: using end instead of Math.max(last[1], end) — would shrink to [1,4].
    expect(mergeIntervals([[1, 10], [3, 4]])).toEqual([[1, 10]]);
  });

  // --- touching (boundary of the merge condition) ---
  it("merges touching intervals that share an endpoint", () => {
    // Catches: off-by-one where start == last end (2 <= 2) is treated as disjoint.
    expect(mergeIntervals([[1, 2], [2, 3]])).toEqual([[1, 3]]);
  });

  it("keeps intervals with a gap of 1 separate (just past the touch boundary)", () => {
    // Catches: over-merging where start = last end + 1 (3 > 2) is wrongly merged.
    expect(mergeIntervals([[1, 2], [3, 4]])).toEqual([[1, 2], [3, 4]]);
  });

  // --- disjoint ---
  it("keeps disjoint intervals separate and sorted", () => {
    // Catches: spurious merging of clearly non-overlapping intervals.
    expect(mergeIntervals([[1, 2], [5, 6]])).toEqual([[1, 2], [5, 6]]);
  });

  // --- sorting ---
  it("sorts output by start ascending regardless of input order", () => {
    // Catches: assuming input is pre-sorted; unsorted input would mis-merge.
    expect(mergeIntervals([[5, 6], [1, 2], [3, 4]])).toEqual([
      [1, 2],
      [3, 4],
      [5, 6],
    ]);
  });

  it("merges overlapping intervals given out of order", () => {
    // Catches: merge logic that only works on a pre-sorted array.
    expect(mergeIntervals([[3, 6], [1, 4]])).toEqual([[1, 6]]);
  });

  // --- chaining across multiple intervals ---
  it("merges a chain where each interval overlaps the running merge", () => {
    // Catches: comparing only against the original next interval rather than the
    // extended running interval — [1,3],[2,5],[4,8] must become [1,8].
    expect(mergeIntervals([[1, 3], [2, 5], [4, 8]])).toEqual([[1, 8]]);
  });

  it("does not merge across a later interval that only touches the extended end", () => {
    // Catches: forgetting to update last end to the max — [1,5] extended by [2,10]
    // then [10,12] should touch-merge to [1,12].
    expect(mergeIntervals([[1, 5], [2, 10], [10, 12]])).toEqual([[1, 12]]);
  });

  // --- duplicates ---
  it("collapses duplicate identical intervals", () => {
    // Catches: emitting duplicates instead of a single merged interval.
    expect(mergeIntervals([[1, 2], [1, 2]])).toEqual([[1, 2]]);
  });

  // --- zero-length intervals (start == end) ---
  it("treats a zero-length interval touching another as merged", () => {
    // Catches: mishandling start == end points; [5,5] and [5,7] -> [5,7].
    expect(mergeIntervals([[5, 5], [5, 7]])).toEqual([[5, 7]]);
  });

  it("keeps a standalone zero-length interval", () => {
    // Catches: dropping degenerate [n,n] intervals.
    expect(mergeIntervals([[3, 3]])).toEqual([[3, 3]]);
  });

  // --- negative numbers ---
  it("handles negative coordinates correctly", () => {
    // Catches: sign or comparison bugs across zero.
    expect(mergeIntervals([[-5, -1], [-3, 2]])).toEqual([[-5, 2]]);
  });

  // --- errors (start > end) ---
  it("throws RangeError when a pair has start > end", () => {
    // Catches: missing validation of the start <= end precondition.
    expect(() => mergeIntervals([[5, 1]])).toThrow(RangeError);
  });

  it("does not throw for a valid zero-length pair (start == end)", () => {
    // Catches: an over-strict check using start >= end instead of start > end.
    expect(() => mergeIntervals([[4, 4]])).not.toThrow();
  });

  it("throws for an invalid pair even when other pairs are valid", () => {
    // Catches: validating only the first element or skipping validation on merge.
    expect(() => mergeIntervals([[1, 2], [9, 3]])).toThrow(RangeError);
  });

  // --- immutability ---
  it("does not mutate the input array", () => {
    // Catches: in-place sort of the caller's array.
    const input = [[5, 6], [1, 2]];
    mergeIntervals(input);
    expect(input).toEqual([[5, 6], [1, 2]]);
  });

  it("does not mutate the input pairs", () => {
    // Catches: writing last[1] into a pair the caller still holds a reference to.
    const a = [1, 4];
    const b = [3, 6];
    mergeIntervals([a, b]);
    expect(a).toEqual([1, 4]);
    expect(b).toEqual([3, 6]);
  });

  it("returns a new array distinct from the input", () => {
    // Catches: returning the same array reference (aliasing) for a single interval.
    const input = [[1, 2]];
    const result = mergeIntervals(input);
    expect(result).not.toBe(input);
    expect(result[0]).not.toBe(input[0]);
  });
});

